import React, { useState, useRef, useEffect } from 'react';
import Card from './common/Card';
import Button from './common/Button';
import TextArea from './common/TextArea';
import { createAdvisorChat } from '../services/geminiService';
import { GenerateContentResponse, Chat } from "@google/genai";

interface Message {
    role: 'user' | 'model';
    text: string;
}

const BusinessAdvisor: React.FC = () => {
    const [messages, setMessages] = useState<Message[]>([
        { role: 'model', text: "Hello! I'm your AI Business Advisor. I can help you with questions about South African tax, compliance, marketing strategies, or general business advice. How can I assist you today?" }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const chatSessionRef = useRef<Chat | null>(null);

    useEffect(() => {
        // Initialize chat session on mount
        chatSessionRef.current = createAdvisorChat();

        // Optional: Send initial history if we had stored it
    }, []);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || !chatSessionRef.current) return;

        const userMessage = input.trim();
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
        setIsLoading(true);

        try {
            // Add a placeholder for the model response
            setMessages(prev => [...prev, { role: 'model', text: '' }]);

            const resultStream = await chatSessionRef.current.sendMessageStream({ message: userMessage });

            let fullText = '';
            for await (const chunk of resultStream) {
                 // Check if chunk has text, strictly typed check from prompt guidelines not needed here as we iterate
                 // but good to be safe.
                 const c = chunk as GenerateContentResponse;
                 const chunkText = c.text || '';
                 fullText += chunkText;

                 setMessages(prev => {
                    const newMessages = [...prev];
                    const lastMessage = newMessages[newMessages.length - 1];
                    if (lastMessage.role === 'model') {
                        lastMessage.text = fullText;
                    }
                    return newMessages;
                 });
            }

        } catch (error) {
            console.error("Chat error:", error);
            setMessages(prev => {
                 const newMessages = [...prev];
                 const lastMessage = newMessages[newMessages.length - 1];
                 if (lastMessage.role === 'model' && lastMessage.text === '') {
                     // If we failed before getting any text
                     lastMessage.text = "I apologize, but I encountered an error. Please try asking again.";
                 } else {
                     // If we failed mid-stream
                     newMessages.push({ role: 'model', text: "\n[System: Connection interrupted. Please try again.]" });
                 }
                 return newMessages;
            });
        } finally {
            setIsLoading(false);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSubmit(e as any);
        }
    };

    return (
        <div className="max-w-4xl mx-auto h-[calc(100vh-140px)] flex flex-col">
            <Card className="flex-1 flex flex-col overflow-hidden !p-0">
                <div className="bg-indigo-600 p-4 text-white flex justify-between items-center">
                    <div>
                        <h2 className="font-semibold text-lg">AI Business Advisor</h2>
                        <p className="text-indigo-200 text-xs">Powered by Gemini 2.5</p>
                    </div>
                     <div className="bg-indigo-500 rounded-full p-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[80%] rounded-2xl p-4 shadow-sm ${
                                msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-none' 
                                : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                            }`}>
                                <p className="whitespace-pre-wrap text-sm leading-relaxed">{msg.text}</p>
                            </div>
                        </div>
                    ))}
                    <div ref={messagesEndRef} />
                </div>

                <div className="p-4 bg-white border-t border-slate-200">
                    <form onSubmit={handleSubmit} className="relative">
                        <textarea
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={handleKeyDown}
                            placeholder="Ask about compliance, marketing, or strategy..."
                            className="w-full pl-4 pr-12 py-3 rounded-xl border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-none shadow-sm text-sm"
                            rows={2}
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim()}
                            className="absolute right-2 bottom-2.5 p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:bg-indigo-300 transition-colors"
                        >
                            {isLoading ? (
                                <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            ) : (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-8.707l-3-3a1 1 0 00-1.414 1.414L10.586 9H7a1 1 0 100 2h3.586l-1.293 1.293a1 1 0 101.414 1.414l3-3a1 1 0 000-1.414z" clipRule="evenodd" /></svg>
                            )}
                        </button>
                    </form>
                    <p className="text-center text-xs text-slate-400 mt-2">AI can make mistakes. Check important info.</p>
                </div>
            </Card>
        </div>
    );
};

export default BusinessAdvisor;

