          activeTool={activeTool}
          onMenuClick={() => setSidebarOpen(!isSidebarOpen)}
        />
        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 sm:p-6 lg:p-8">
          {renderActiveTool()}
        </main>
      </div>
    </div>
  );
};

