import React, { useState, useEffect } from 'react';
import Card from './common/Card';
import Button from './common/Button';
import FileUpload from './common/FileUpload';
import { analyzeReceipt } from '../services/geminiService';
import type { Expense } from '../types';

const STORAGE_KEY = 'sme-pal-expenses';

const ReceiptScanner: React.FC = () => {
    const [expenses, setExpenses] = useState<Expense[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [currentFile, setCurrentFile] = useState<File | null>(null);
    const [error, setError] = useState('');

    useEffect(() => {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
            setExpenses(JSON.parse(stored));
        }
    }, []);

    const saveExpenses = (newExpenses: Expense[]) => {
        setExpenses(newExpenses);
        localStorage.setItem(STORAGE_KEY, JSON.stringify(newExpenses));
    };

    const handleFileSelect = (file: File) => {
        setCurrentFile(file);
        setError('');
    };

    const handleProcessReceipt = async () => {
        if (!currentFile) return;

        setIsProcessing(true);
        setError('');

        try {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const base64String = reader.result as string;
                try {
                    const analysis = await analyzeReceipt(base64String, currentFile.type);

                    const newExpense: Expense = {
                        id: crypto.randomUUID(),
                        ...analysis,
                        // If date is invalid or missing from AI, default to today
                        date: analysis.date || new Date().toISOString().split('T')[0]
                    };

                    saveExpenses([newExpense, ...expenses]);
                    setCurrentFile(null); // Clear file input after success
                } catch (err: any) {
                    setError(err.message);
                } finally {
                    setIsProcessing(false);
                }
            };
            reader.readAsDataURL(currentFile);
        } catch (e) {
            setError("Failed to read file.");
            setIsProcessing(false);
        }
    };

    const deleteExpense = (id: string) => {
        if (window.confirm("Delete this expense record?")) {
            saveExpenses(expenses.filter(e => e.id !== id));
        }
    };

    return (
        <div className="max-w-5xl mx-auto space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* Upload Section */}
                <div className="md:col-span-1">
                    <Card title="Scan Receipt">
                        <div className="space-y-4">
                            <p className="text-sm text-gray-600">Upload a photo of a receipt. Our AI will extract the details for you.</p>
                            <FileUpload
                                label="Receipt Image (JPG, PNG)"
                                id="receipt-upload"
                                onFileSelect={handleFileSelect}
                                onFileRemove={() => setCurrentFile(null)}
                                acceptedFileTypes="image/jpeg, image/png, image/webp"
                                currentFile={currentFile}
                                maxSizeMB={4}
                            />
                            <Button 
                                onClick={handleProcessReceipt} 
                                disabled={!currentFile} 
                                isLoading={isProcessing} 
                                className="w-full"
                            >
                                {isProcessing ? 'Analyzing...' : 'Extract & Save'}
                            </Button>
                            {error && <p className="text-sm text-red-600 bg-red-50 p-2 rounded">{error}</p>}
                        </div>
                    </Card>
                </div>

                {/* List Section */}
                <div className="md:col-span-2">
                    <Card title="Expense Log">
                        {expenses.length === 0 ? (
                            <div className="text-center py-10 text-gray-500">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mx-auto mb-3 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                <p>No expenses scanned yet.</p>
                            </div>
                        ) : (
                            <div className="overflow-x-auto">
                                <table className="min-w-full divide-y divide-gray-200">
                                    <thead className="bg-gray-50">
                                        <tr>
                                            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                                            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Merchant</th>
                                            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                                            <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                                            <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody className="bg-white divide-y divide-gray-200">
                                        {expenses.map((expense) => (
                                            <tr key={expense.id}>
                                                <td className="px-4 py-3 text-sm text-gray-900 whitespace-nowrap">{expense.date}</td>
                                                <td className="px-4 py-3 text-sm font-medium text-gray-900">{expense.merchant}</td>
                                                <td className="px-4 py-3 text-sm text-gray-500"><span className="px-2 py-1 bg-indigo-50 text-indigo-700 rounded-full text-xs">{expense.category}</span></td>
                                                <td className="px-4 py-3 text-sm text-gray-900 text-right font-mono">R {expense.amount.toFixed(2)}</td>
                                                <td className="px-4 py-3 text-right text-sm font-medium">
                                                    <button onClick={() => deleteExpense(expense.id)} className="text-red-600 hover:text-red-900">
                                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                                    </button>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </Card>
                </div>
            </div>
        </div>
    );
};

export default ReceiptScanner;

import React, { useState } from 'react';
import Card from './common/Card';
import Input from './common/Input';
import TextArea from './common/TextArea';
import Button from './common/Button';
import { generateMarketingContent } from '../services/geminiService';
import type { MarketingContent } from '../types';

const platforms = ['LinkedIn', 'Facebook', 'Instagram', 'Twitter/X', 'Email Newsletter'];

const MarketingAssistant: React.FC = () => {
    const [topic, setTopic] = useState('');
    const [audience, setAudience] = useState('');
    const [platform, setPlatform] = useState('LinkedIn');
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<MarketingContent | null>(null);
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setResult(null);

        try {
            const content = await generateMarketingContent(topic, platform, audience);
            setResult(content);
        } catch (err: any) {
            setError(err.message || 'An unexpected error occurred.');
        } finally {
            setLoading(false);
        }
    };

    const copyToClipboard = (text: string) => {
        navigator.clipboard.writeText(text);
        alert('Copied to clipboard!');
    };

    return (
        <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-8">
            <Card title="Marketing Content Generator">
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label htmlFor="platform" className="block text-sm font-medium text-gray-700 mb-1">Platform</label>
                        <select 
                            id="platform" 
                            value={platform} 
                            onChange={(e) => setPlatform(e.target.value)}
                            className="form-input"
                        >
                            {platforms.map(p => <option key={p} value={p}>{p}</option>)}
