                    </div>
                    <Input 
                        label="Product / Service / Topic" 
                        id="topic" 
                        value={topic} 
                        onChange={(e) => setTopic(e.target.value)}
                        placeholder="e.g., Summer Sale on Leather Boots" 
                        required 
                    />
                    <TextArea 
                        label="Target Audience" 
                        id="audience" 
                        value={audience} 
                        onChange={(e) => setAudience(e.target.value)} 
                        rows={2} 
                        placeholder="e.g., Young professionals in Johannesburg"
                        required 
                    />
                    <Button type="submit" isLoading={loading} className="w-full">
                        Generate Content
                    </Button>
                </form>
            </Card>

            <div className="space-y-6">
                {loading && (
                    <Card>
                        <div className="text-center py-10 text-gray-500 animate-pulse">
                            Thinking creatively...
                        </div>
                    </Card>
                )}

                {error && (
                    <Card>
                        <div className="text-red-600 bg-red-50 p-4 rounded-md">{error}</div>
                    </Card>
                )}

                {result && !loading && (
                    <Card title="Generated Content">
                        <div className="space-y-4">
