                                    ))}
                                </div>
                            </div>

                            <div className="bg-yellow-50 border border-yellow-100 p-3 rounded-md">
                                <h4 className="text-xs font-bold text-yellow-800 uppercase tracking-wide mb-1">Image Idea</h4>
                                <p className="text-sm text-yellow-800 italic">{result.imageIdea}</p>
                            </div>

                            <div className="flex justify-end pt-2">
                                <Button variant="secondary" onClick={() => copyToClipboard(result.content)}>
                                    Copy Text
                                </Button>
                            </div>
                        </div>
                    </Card>
                )}

                {!result && !loading && !error && (
                    <div className="hidden md:block opacity-50 text-center pt-10">
