                                onChange={handleLoadTemplate} 
                                className="block w-full py-2 px-3 border border-gray-300 bg-white rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                            >
                                <option value="">-- Select a Template --</option>
                                {templates.map(t => (
                                    <option key={t.id} value={t.id}>{t.name}</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex gap-2">
                             <Button variant="secondary" onClick={handleSaveTemplate} className="!py-2 !px-3 text-sm whitespace-nowrap">
                                Save Current
                            </Button>
                            {selectedTemplateId && (
                                <Button variant="danger" onClick={handleDeleteTemplate} className="!py-2 !px-3 text-sm" title="Delete selected template">
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                    </svg>
                                </Button>
                            )}
                        </div>
                    </div>

                    {/* FROM/TO SECTION */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
