                                    <div className="flex justify-between">
                                        <span>Company Registration Service</span>
                                        <span>R 499.00</span>
                                    </div>
                                    <div className="flex justify-between font-semibold text-gray-800 border-t pt-2">
                                        <span>Total Due</span>
                                        <span>R 499.00</span>
                                    </div>
                                </div>
                            </div>
                            <form onSubmit={handlePaymentSubmit} className="space-y-4">
                                 <div>
                                    <Input label="Cardholder Name" id="cardholderName" value={paymentDetails.cardholderName} onChange={handlePaymentInputChange} required disabled={isPaying} className={paymentErrors.cardholderName ? 'border-red-500' : ''}/>
                                    {paymentErrors.cardholderName && <p className="mt-1 text-xs text-red-600">{paymentErrors.cardholderName}</p>}
                                </div>
                                <div>
                                    <Input label="Card Number" id="cardNumber" value={paymentDetails.cardNumber} onChange={handlePaymentInputChange} placeholder="0000 0000 0000 0000" required disabled={isPaying} className={paymentErrors.cardNumber ? 'border-red-500' : ''}/>
                                     {paymentErrors.cardNumber && <p className="mt-1 text-xs text-red-600">{paymentErrors.cardNumber}</p>}
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                     <div>
                                        <Input label="Expiry Date (MM/YY)" id="expiryDate" value={paymentDetails.expiryDate} onChange={handlePaymentInputChange} placeholder="MM/YY" required disabled={isPaying} className={paymentErrors.expiryDate ? 'border-red-500' : ''}/>
                                        {paymentErrors.expiryDate && <p className="mt-1 text-xs text-red-600">{paymentErrors.expiryDate}</p>}
                                    </div>
                                     <div>
                                        <Input label="CVC" id="cvc" value={paymentDetails.cvc} onChange={handlePaymentInputChange} placeholder="123" required disabled={isPaying} className={paymentErrors.cvc ? 'border-red-500' : ''}/>
                                        {paymentErrors.cvc && <p className="mt-1 text-xs text-red-600">{paymentErrors.cvc}</p>}
                                    </div>
                                </div>
                                <Button type="submit" isLoading={isPaying} className="w-full !py-3">
                                    {isPaying ? 'Processing Payment...' : 'Pay & Complete Registration'}
                                </Button>
                            </form>
                        </div>
                    </Card>
                )}

                {step === 8 && (
                    <Card>
                        <div className="text-center py-12">
                            <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-green-100">
                                <svg className="h-10 w-10 text-green-600" fill="none" viewBox="0 0 24 24" strokeWidth="1.5" stroke="currentColor" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>
                            </div>
                            <h3 className="mt-4 text-2xl font-semibold leading-6 text-gray-900">Registration Submitted!</h3>
                            <div className="mt-2">
                                <p className="text-md text-gray-600">
                                    Thank you! We have received your application and payment. We will begin processing it shortly and keep you updated via email.
                                </p>
                                <p className="mt-4 text-sm text-gray-500 bg-slate-50 p-2 rounded-md inline-block">
                                    Transaction ID: <span className="font-mono">{transactionId}</span>
                                </p>
                            </div>
                            <div className="mt-8">
                                <Button onClick={resetWizard}>Start Another Registration</Button>
                            </div>
                        </div>
                    </Card>
                )}

                {step < 8 && (
                    <div className="flex justify-between items-center pt-6">
                        <div className="flex gap-2">
                            {step > 1 && (<Button type="button" variant="secondary" onClick={prevStep} disabled={isPaying}>Back</Button>)}
                            {step === 1 && (<Button type="button" variant="secondary" onClick={() => setStep(0)}>Change Type</Button>)}
                            {/* Option to clear progress manually if stuck */}
                            {step > 0 && <Button type="button" variant="danger" onClick={resetWizard} className="!bg-red-50 !text-red-600 !border-red-200 hover:!bg-red-100">Reset Form</Button>}
                        </div>
                        <div>
                            {step < 6 && (<Button type="button" onClick={nextStep}>Next Step</Button>)}
                            {step === 6 && (<Button type="button" onClick={nextStep}>Proceed to Payment</Button>)}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

