  fromBusinessNumber?: string;
  fromVatNumber?: string;
  toName: string;
  toAddress: string;
  toBusinessNumber?: string;
  toVatNumber?: string;
  invoiceNumber: string;
  date: string;
  paymentTerms?: string;
  paymentLink?: string;
  bankDetails?: string;
  items: InvoiceItem[];
  notes: string;
  header?: string;
  footer?: string;
  companyLogo?: string;
  theme?: InvoiceTheme;
}

export interface TaxCalculationResult {
  taxableIncome: string;
  estimatedTax: string;
  notes: string[];
}

export interface GeneratedContract {
    title: string;
    clauses: {
        heading: string;
        body: string;
    }[];
}

export interface Client {
