  businessPhysicalAddress: string;
  businessPostalAddress: string;
  yearEnd: string;
  directors: Director[];
  primaryContact: {
    name: string;
    email: string;
  };
  directorIdDocuments: Record<string, File | null>; // Keyed by director ID
  businessAddressProof: File | null;
