);

const initialFormData: CompanyRegistrationData = {
    companyType: CompanyType.PRIVATE_COMPANY,
    names: { name1: '', name2: '', name3: '', name4: '' },
    businessPhysicalAddress: '',
    businessPostalAddress: '',
    yearEnd: 'February',
    directors: [],
    primaryContact: { name: '', email: '' },
    directorIdDocuments: {},
    businessAddressProof: null,
};

const STORAGE_KEY = 'sme-pal-company-reg-progress';

const CompanyRegistration: React.FC = () => {
    const [step, setStep] = useState(0); // 0 for type selection
    const [nameSuggestionDescription, setNameSuggestionDescription] = useState('An online store selling handmade leather goods in South Africa');
    const [suggestedNames, setSuggestedNames] = useState<string[]>([]);
    const [isSuggesting, setIsSuggesting] = useState(false);
    const [suggestionError, setSuggestionError] = useState('');

    const [formData, setFormData] = useState<CompanyRegistrationData>(initialFormData);

    const [paymentDetails, setPaymentDetails] = useState({ cardholderName: '', cardNumber: '', expiryDate: '', cvc: '' });
    const [paymentErrors, setPaymentErrors] = useState<PaymentValidationErrors>({});
    const [isPaying, setIsPaying] = useState(false);
    const [transactionId, setTransactionId] = useState('');


    // Persistence Logic
    useEffect(() => {
        try {
            const savedData = localStorage.getItem(STORAGE_KEY);
            if (savedData) {
                const parsed = JSON.parse(savedData);
                // We need to be careful with Files, they cannot be stored in localStorage.
                // We will load text data but Files will need to be re-uploaded by the user.
                setFormData(prev => ({
                    ...prev,
                    ...parsed.formData,
                    // Reset file objects as they can't be hydrated from JSON
                    directorIdDocuments: {},
                    businessAddressProof: null
                }));
                // Only restore step if it wasn't the success step
                if (parsed.step < 8) {
                    setStep(parsed.step);
                }
            }
        } catch (e) {
            console.error("Failed to load saved registration progress", e);
        }
    }, []);

    useEffect(() => {
        // Save progress whenever step or formData changes (excluding file objects)
        const dataToSave = {
            step,
            formData: {
                ...formData,
                directorIdDocuments: {},
                businessAddressProof: null
            }
        };
        localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
    }, [step, formData]);


    const steps = useMemo(() => [
        { id: 1, name: 'Company Names' },
        { id: 2, name: 'Business Details' },
        { id: 3, name: 'Directors & Shareholding' },
        { id: 4, name: 'Documents' },
        { id: 5, name: 'Primary Contact' },
        { id: 6, name: 'Review' },
        { id: 7, name: 'Payment' },
        { id: 8, name: 'Complete' }
    ], []);
    const totalSteps = steps.length;

    const handleSelectCompanyType = (type: CompanyType) => {
        setFormData(prev => ({ ...prev, companyType: type }));
        setStep(1);
    };

    const resetWizard = () => {
        localStorage.removeItem(STORAGE_KEY);
        setFormData(initialFormData);
        setStep(0);
        setTransactionId('');
    }

    const handleNameSuggestion = async () => {
        setIsSuggesting(true);
        setSuggestionError('');
        setSuggestedNames([]);
        try {
            const names = await suggestCompanyNames(nameSuggestionDescription);
            setSuggestedNames(names);
        } catch (err: any) {
            setSuggestionError(err.message || 'Failed to suggest names.');
        } finally {
            setIsSuggesting(false);
        }
    };

    const handleNestedFormChange = (section: 'names' | 'primaryContact', field: string, value: string) => {
        setFormData(prev => ({
            ...prev,
            [section]: {
                ...(prev[section] as any),
                [field]: value
            }
        }));
    };

    const addDirector = () => {
        const newDirector: Director = {
            id: crypto.randomUUID(),
            fullName: '',
            identificationType: 'SA ID',
            identificationNumber: '',
            phone: '',
            email: '',
            physicalAddress: '',
            postalAddress: '',
            shareholding: 0,
        };
        setFormData(prev => ({ ...prev, directors: [...prev.directors, newDirector] }));
    };

    const updateDirector = (updatedDirector: Director) => {
        setFormData(prev => ({
            ...prev,
            directors: prev.directors.map(d => d.id === updatedDirector.id ? updatedDirector : d)
        }));
    };

    const removeDirector = (id: string) => {
        setFormData(prev => {
            const newDirectors = prev.directors.filter(d => d.id !== id);
            const newDirectorIdDocuments = { ...prev.directorIdDocuments };
            delete newDirectorIdDocuments[id];
            return {
                ...prev,
                directors: newDirectors,
                directorIdDocuments: newDirectorIdDocuments
            };
        });
    };

    const handleUseSuggestedName = (name: string) => {
        const { names } = formData;
        const newNames = { ...names };
        if (!names.name1) newNames.name1 = name;
        else if (!names.name2) newNames.name2 = name;
        else if (!names.name3) newNames.name3 = name;
        else if (!names.name4) newNames.name4 = name;
        else newNames.name4 = name; // Overwrite last one if all are full
        setFormData(prev => ({ ...prev, names: newNames }));
    };

    const copyBusinessAddress = () => {
        setFormData(prev => ({ ...prev, businessPostalAddress: prev.businessPhysicalAddress }));
    };

    const nextStep = () => {
        // Validation before proceeding
        if (step === 1 && !formData.names.name1) {
            alert('Please provide at least one proposed company name.');
            return;
        }
        if (step === 2 && (!formData.businessPhysicalAddress || !formData.businessPostalAddress)) {
            alert('Please provide both physical and postal business addresses.');
            return;
        }
        if (step === 3) {
            if (formData.directors.length === 0) {
                alert('You must add at least one director.');
                return;
            }
            // NPC Specific check
            if (formData.companyType === CompanyType.NON_PROFIT_COMPANY && formData.directors.length < 3) {
                alert('A Non-Profit Company (NPC) must have at least 3 directors by law.');
                return;
            }
            // Check Shareholding Total (usually for Pty Ltd, NPC doesn't have shares in the same way, but MOI defines control)
            if (formData.companyType === CompanyType.PRIVATE_COMPANY) {
                const totalShareholding = formData.directors.reduce((sum, d) => sum + d.shareholding, 0);
                if (Math.abs(totalShareholding - 100) > 0.1) {
                    if (!window.confirm(`Total shareholding is ${totalShareholding}%. It should ideally be 100%. Do you want to verify this later?`)) {
                        return;
                    }
                }
            }
        }
        if (step === 4) {
            const allDocsUploaded = formData.directors.every(dir => !!formData.directorIdDocuments[dir.id]);
            if (!allDocsUploaded || !formData.businessAddressProof) {
                alert('Please upload all required documents.');
                return;
            }
        }
        if (step === 5) {
            if (!formData.primaryContact.name || !formData.primaryContact.email) {
                alert('Please provide the primary contact details.');
                return;
            }
        }
        setStep(prev => Math.min(prev + 1, totalSteps));
    };

    const prevStep = () => setStep(prev => Math.max(prev - 1, 1));

    const submitRegistrationData = () => {
        for (const director of formData.directors) {
            const error = validateIdNumber(director.identificationType, director.identificationNumber);
            if (error) {
                alert(`Error for Director ${director.fullName || ' '}: ${error}`);
                setStep(3); // Go back to director step
                return;
            }
        }

        console.log('Company Registration Data:', formData);
        // This is where you would send the data to a server in a real application.
    };

    const handlePaymentInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { id, value } = e.target;
        let formattedValue = value;
        if (id === 'cardNumber') {
            formattedValue = value.replace(/[^\d]/g, '').replace(/(.{4})/g, '$1 ').trim();
            if (formattedValue.length > 19) formattedValue = formattedValue.substring(0, 19);
        }
        if (id === 'expiryDate') {
            formattedValue = value.replace(/[^\d]/g, '');
            if (formattedValue.length > 2) {
                formattedValue = `${formattedValue.slice(0, 2)}/${formattedValue.slice(2, 4)}`;
            }
        }
        if (id === 'cvc') {
            formattedValue = value.replace(/[^\d]/g, '').slice(0, 4);
        }
        setPaymentDetails(prev => ({ ...prev, [id]: formattedValue }));
    };

    const handlePaymentSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setPaymentErrors({});

        const errors = validatePaymentDetails(paymentDetails);
        if (Object.keys(errors).length > 0) {
            setPaymentErrors(errors);
            return;
        }

        setIsPaying(true);
        // Simulate API call to payment gateway
        await new Promise(resolve => setTimeout(resolve, 2500));

        console.log('Payment successful. Submitting registration data...');
        submitRegistrationData();

        // Clear saved progress on success
        localStorage.removeItem(STORAGE_KEY);

        setTransactionId(`TXN-${crypto.randomUUID().split('-')[0].toUpperCase()}`);
        setIsPaying(false);
        setStep(8); // Go to the final "Complete" step
    };


    if (step === 0) {
        return (
            <div className="max-w-4xl mx-auto space-y-8 pb-10">
                <div className="text-center space-y-2">
                    <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Register Your Company</h1>
                    <p className="text-lg text-slate-600">Select your entity type and let's get your business legally recognized.</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <CompanyTypeCard
                        type={CompanyType.PRIVATE_COMPANY}
                        description="A for-profit company, the most common type for businesses in South Africa (Pty Ltd). Requires minimum 1 director."
                        onSelect={() => handleSelectCompanyType(CompanyType.PRIVATE_COMPANY)}
                        icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>}
                    />
                    <CompanyTypeCard
                        type={CompanyType.NON_PROFIT_COMPANY}
                        description="Organisations for public benefit or social objectives. Requires minimum 3 directors and a clear social mandate."
                        onSelect={() => handleSelectCompanyType(CompanyType.NON_PROFIT_COMPANY)}
                        icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M15 21v-2a6 6 0 00-12 0v2" /></svg>}
                    />
                </div>

                <Card>
                    <div className="flex items-start gap-4">
                        <div className="bg-indigo-100 p-3 rounded-xl text-indigo-600 flex-shrink-0">
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" /></svg>
                        </div>
                        <div className="flex-1 text-left">
                            <h2 className="text-lg font-bold text-slate-800 mb-4">Preparation Checklist</h2>
                            <p className="text-sm text-slate-600 mb-6">Before you begin, ensure you have clear, digital copies of the following documents. These are mandatory legal requirements for CIPC registration in South Africa.</p>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <h4 className="font-bold text-slate-800 text-sm mb-1">Certified SA ID or Passport</h4>
                                    <ul className="text-xs text-slate-500 list-disc list-inside space-y-1">
                                        <li>Pty Ltd: Min 1 Director</li>
                                        <li>NPC: Min 3 Directors</li>
                                        <li>Certification &lt; 3 months old</li>
                                    </ul>
                                    <p className="mt-2 text-[10px] text-indigo-600 font-semibold uppercase">Why? Verification of identity prevents identity theft and company hijacking.</p>
                                </div>
                                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <h4 className="font-bold text-slate-800 text-sm mb-1">Director Residence Proof</h4>
                                    <p className="text-xs text-slate-500">Utility bill or bank statement in each director's name (&lt; 3 months old).</p>
                                    <p className="mt-2 text-[10px] text-indigo-600 font-semibold uppercase">Why? Required for FICA compliance to confirm physical presence of stakeholders.</p>
                                </div>
                                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <h4 className="font-bold text-slate-800 text-sm mb-1">NPC Social Objectives</h4>
                                    <p className="text-xs text-slate-500">For NPCs: A clear description of the social benefit or public goal.</p>
                                    <p className="mt-2 text-[10px] text-indigo-600 font-semibold uppercase">Why? To verify the entity is not-for-profit and qualifies for NPC status.</p>
                                </div>
                                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <h4 className="font-bold text-slate-800 text-sm mb-1">Business Physical Address</h4>
                                    <p className="text-xs text-slate-500">A valid SA address where business records will be kept.</p>
                                    <p className="mt-2 text-[10px] text-indigo-600 font-semibold uppercase">Why? Legally required for service of official CIPC and SARS notices.</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </Card>
            </div>
        )
    }

    return (
        <div className="max-w-4xl mx-auto space-y-6">
            <div className="text-center">
                 <h1 className="text-2xl font-bold text-slate-800">Company Registration Wizard</h1>
                 <p className="text-slate-600">Registering a: <span className="font-semibold text-indigo-600">{formData.companyType}</span></p>
            </div>

            <div className="border border-gray-200 rounded-xl p-4 sm:p-6 bg-white shadow-sm overflow-x-auto">
                <nav aria-label="Progress" className="min-w-[600px]">
                    <ol role="list" className="flex items-center">
                        {steps.map((s, index) => (
                            <li key={s.name} className={`relative ${index !== steps.length - 1 ? 'pr-8 sm:pr-20' : ''} flex-1`}>
                                {step > s.id ? (
                                    <>
                                        <div className="absolute inset-0 flex items-center" aria-hidden="true">
                                            <div className="h-0.5 w-full bg-indigo-600" />
                                        </div>
                                        <button onClick={() => setStep(s.id)} className="relative flex h-8 w-8 items-center justify-center rounded-full bg-indigo-600 hover:bg-indigo-900 transition-colors">
                                            <svg className="h-5 w-5 text-white" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true"><path fillRule="evenodd" d="M16.704 4.153a.75.75 0 01.143 1.052l-8 10.5a.75.75 0 01-1.127.075l-4.5-4.5a.75.75 0 011.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 011.052-.143z" clipRule="evenodd" /></svg>
                                            <span className="sr-only">{s.name}</span>
                                        </button>
                                    </>
                                ) : step === s.id ? (
                                    <>
                                        <div className="absolute inset-0 flex items-center" aria-hidden="true">
                                            <div className="h-0.5 w-full bg-gray-200" />
                                        </div>
                                        <div className="relative flex h-8 w-8 items-center justify-center rounded-full border-2 border-indigo-600 bg-white" aria-current="step">
                                            <span className="h-2.5 w-2.5 rounded-full bg-indigo-600" aria-hidden="true" />
                                            <span className="sr-only">{s.name}</span>
                                        </div>
                                    </>
                                ) : (
                                    <>
                                        <div className="absolute inset-0 flex items-center" aria-hidden="true">
                                            <div className="h-0.5 w-full bg-gray-200" />
                                        </div>
                                        <div className="group relative flex h-8 w-8 items-center justify-center rounded-full border-2 border-gray-300 bg-white hover:border-gray-400">
                                            <span className="h-2.5 w-2.5 rounded-full bg-transparent group-hover:bg-gray-300" aria-hidden="true" />
                                            <span className="sr-only">{s.name}</span>
                                        </div>
                                    </>
                                )}
                                <div className="absolute -bottom-6 text-xs text-center w-24 -left-8 sm:w-auto sm:left-auto">{s.name}</div>
                            </li>
                        ))}
                    </ol>
                </nav>
            </div>

            <div className="pb-10">
                {step === 1 && (
                    <div className="space-y-6">
                        <Card title="Step 1: Get Company Name Suggestions (Optional)">
                            <div className="space-y-4">
                                <TextArea label="Describe your business / organization" id="businessDescription" value={nameSuggestionDescription} onChange={e => setNameSuggestionDescription(e.target.value)} rows={3} />
                                <Button type="button" onClick={handleNameSuggestion} isLoading={isSuggesting} className="w-full">Suggest Names</Button>
                                {suggestionError && <p className="text-red-500 text-sm">{suggestionError}</p>}
                                {suggestedNames.length > 0 && (
                                    <div className="pt-4"><h4 className="font-semibold text-gray-800 mb-2 text-left">Suggestions:</h4><div className="flex flex-wrap gap-2">{suggestedNames.map(name => (<button key={name} type="button" onClick={() => handleUseSuggestedName(name)} className="bg-indigo-100 text-indigo-700 text-sm font-medium px-3 py-1 rounded-full hover:bg-indigo-200 transition-colors" title={`Use "${name}" in form`}>{name}</button>))}</div></div>
                                )}
                            </div>
                        </Card>
                        <Card title="Proposed Company Names">
                             <p className="text-sm text-gray-600 mb-4 text-left">Provide up to 4 names in order of preference.</p>
                             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <Input label="Name 1 (Highest Preference)" id="name1" value={formData.names.name1} onChange={e => handleNestedFormChange('names', 'name1', e.target.value)} required />
                                <Input label="Name 2" id="name2" value={formData.names.name2} onChange={e => handleNestedFormChange('names', 'name2', e.target.value)} />
                                <Input label="Name 3" id="name3" value={formData.names.name3} onChange={e => handleNestedFormChange('names', 'name3', e.target.value)} />
                                <Input label="Name 4" id="name4" value={formData.names.name4} onChange={e => handleNestedFormChange('names', 'name4', e.target.value)} />
                             </div>
                        </Card>
                    </div>
                )}

                {step === 2 && (
                     <Card title="Step 2: Business Details">
                        <div className="space-y-6">
                            <fieldset className="space-y-4 text-left">
                                <legend className="text-lg font-semibold text-gray-900 pb-2 w-full">Business Address</legend>
                                <TextArea label="Physical Address" id="businessPhysicalAddress" value={formData.businessPhysicalAddress} onChange={e => setFormData(p => ({...p, businessPhysicalAddress: e.target.value}))} required />
                                <div className="relative">
                                    <TextArea label="Postal Address" id="businessPostalAddress" value={formData.businessPostalAddress} onChange={e => setFormData(p => ({...p, businessPostalAddress: e.target.value}))} required />
                                    <div className="absolute top-0 right-0">
                                        <button 
                                            type="button"
                                            onClick={copyBusinessAddress}
                                            className="text-xs text-indigo-600 hover:text-indigo-800 cursor-pointer underline"
                                        >
                                            Same as Physical
                                        </button>
                                    </div>
                                </div>
                            </fieldset>
                            <fieldset className="space-y-4 text-left">
                                <legend className="text-lg font-semibold text-gray-900 border-t border-gray-100 pt-4 pb-2 w-full">Financial Details</legend>
                                <div>
                                    <div className="flex items-center mb-1">
                                        <label htmlFor="yearEnd" className="block text-sm font-medium text-gray-700">Financial Year End</label>
                                        <Tooltip content="The month your financial year ends (usually February for individuals/sole props in SA).">
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 ml-1 text-gray-400 hover:text-gray-600 cursor-help" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                                            </svg>
                                        </Tooltip>
                                    </div>
                                    <select id="yearEnd" value={formData.yearEnd} onChange={e => setFormData(p => ({...p, yearEnd: e.target.value}))} className="form-input mt-1">
                                        {['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'].map(month => (<option key={month} value={month}>{month}</option>))}
                                    </select>
                                </div>
                            </fieldset>
                        </div>
                    </Card>
                )}

                {step === 3 && (
                     <Card title="Step 3: Directors & Control">
                        <div className="text-left space-y-4">
                            {formData.companyType === CompanyType.NON_PROFIT_COMPANY ? (
                                <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100 mb-6">
                                    <p className="text-sm text-indigo-800 font-semibold mb-2 flex items-center">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                        NPC Legal Requirement
                                    </p>
                                    <p className="text-xs text-indigo-700">A Non-Profit Company (NPC) must have a minimum of <span className="font-bold underline">3 directors</span> at all times to be valid under the Companies Act.</p>
                                </div>
                            ) : (
                                <p className="text-sm text-gray-600 mb-4">Add all directors of the company. For a Pty Ltd, you must have at least one director.</p>
                            )}

                            <div className="space-y-4">
                                {formData.directors.map((director, index) => (<DirectorForm key={director.id} director={director} onUpdate={updateDirector} onRemove={removeDirector} index={index}/>))}

                                <div className="flex justify-between items-center bg-indigo-50 p-4 rounded-lg">
                                    <div>
                                        {formData.companyType === CompanyType.PRIVATE_COMPANY && (
                                            <>
                                                <span className="font-semibold text-indigo-900 text-sm">Total Shareholding:</span>
                                                <span className={`ml-2 font-bold ${Math.abs(formData.directors.reduce((s,d) => s + d.shareholding, 0) - 100) < 0.1 ? 'text-green-600' : 'text-red-500'}`}>
                                                    {formData.directors.reduce((s,d) => s + d.shareholding, 0).toFixed(2)}%
                                                </span>
                                            </>
                                        )}
                                        {formData.companyType === CompanyType.NON_PROFIT_COMPANY && (
                                            <span className="font-semibold text-indigo-900 text-sm">Directors Count: {formData.directors.length} (Min: 3)</span>
                                        )}
                                    </div>
                                    <Button type="button" variant="secondary" onClick={addDirector}>Add Director</Button>
                                </div>

                                {formData.directors.length === 0 && <p className="text-sm text-red-600">You must add at least one director.</p>}
                            </div>
                        </div>
                    </Card>
                )}

                {step === 4 && (
                    <Card title="Step 4: Upload Required Documents">
                         <div className="bg-amber-50 border-l-4 border-amber-400 p-4 mb-6 text-left">
                            <div className="flex">
                                <div className="flex-shrink-0">
                                <svg className="h-5 w-5 text-amber-400" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
                                    <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                                </svg>
                                </div>
                                <div className="ml-3">
                                <p className="text-sm text-amber-700 font-bold">
                                    CIPC / Legality Notice
                                </p>
                                <p className="text-xs text-amber-700 mt-1">
                                    IDs must be <span className="font-bold underline">certified</span> (within 3 months) to confirm you are the true applicant. Proof of address is required by the <span className="italic">Financial Intelligence Centre Act (FICA)</span>.
                                </p>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-6 text-left">
                            <div className="p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <h3 className="text-md font-semibold text-gray-900">Registered Office Address Proof</h3>
                                <p className="text-xs text-gray-500 mb-3">Upload a utility bill or lease agreement for the physical business location.</p>
                                <FileUpload
                                    label="PDF, PNG, JPG up to 5MB"
                                    id="business-address-proof"
                                    currentFile={formData.businessAddressProof}
                                    onFileSelect={(file) => setFormData(p => ({ ...p, businessAddressProof: file }))}
                                    onFileRemove={() => setFormData(p => ({ ...p, businessAddressProof: null }))}
                                />
                                <p className="mt-3 text-[10px] text-slate-400 italic">Why? CIPC requires a verifiable SA address where legal process can be served.</p>
                            </div>

                            {formData.directors.map((director) => (
                                <div key={director.id} className="pt-6 border-t border-gray-200">
                                    <h3 className="text-md font-semibold text-gray-900">Certified ID for {director.fullName || `Director ${formData.directors.indexOf(director) + 1}`}</h3>
                                    <p className="text-xs text-gray-500 mb-3">Ensure the certification stamp is clear, dated, and signed by a commissioner of oaths.</p>
                                     <FileUpload
                                        label="PDF, PNG, JPG up to 5MB"
                                        id={`director-doc-${director.id}`}
                                        currentFile={formData.directorIdDocuments[director.id] || null}
                                        onFileSelect={(file) => setFormData(prev => ({ ...prev, directorIdDocuments: { ...prev.directorIdDocuments, [director.id]: file } }))}
                                        onFileRemove={() => setFormData(prev => ({ ...prev, directorIdDocuments: { ...prev.directorIdDocuments, [director.id]: null } }))}
                                    />
                                    <div className="mt-2 bg-slate-100 p-2 rounded text-[10px] text-slate-600">
                                        <strong>NPC Note:</strong> If this is an NPC, all {formData.directors.length} directors must provide these docs to confirm collective responsibility.
                                    </div>
                                </div>
                            ))}
                        </div>
                    </Card>
                )}

                {step === 5 && (
                     <Card title="Step 5: Primary Contact">
                        <p className="text-sm text-gray-600 mb-4 text-left">Who should we contact for status updates and certificate delivery?</p>
                        <div className="space-y-4">
                            <Input label="Contact Person Full Name" id="primaryContactName" value={formData.primaryContact.name} onChange={e => handleNestedFormChange('primaryContact', 'name', e.target.value)} required />
                            <Input label="Contact Person Email" id="primaryContactEmail" type="email" value={formData.primaryContact.email} onChange={e => handleNestedFormChange('primaryContact', 'email', e.target.value)} required />
                        </div>
                    </Card>
                )}

                {step === 6 && (
                    <Card title="Step 6: Review & Confirmation">
                        <div className="text-left">
                            <ReviewSection title="Proposed Company Names" data={[
                                { label: 'Name 1', value: formData.names.name1 }, { label: 'Name 2', value: formData.names.name2 }, { label: 'Name 3', value: formData.names.name3 }, { label: 'Name 4', value: formData.names.name4 }
                            ]} />
                             <ReviewSection title="Business Details" data={[
                                { label: 'Company Type', value: formData.companyType }, { label: 'Physical Address', value: formData.businessPhysicalAddress }, { label: 'Postal Address', value: formData.businessPostalAddress }, { label: 'Financial Year End', value: formData.yearEnd }
                            ]} />
                            {formData.directors.map((dir, i) => (
                                <ReviewSection key={dir.id} title={`Director ${i+1} Details`} data={[
                                    { label: 'Full Name', value: dir.fullName }, 
                                    { label: 'Control/Stake', value: formData.companyType === CompanyType.PRIVATE_COMPANY ? `${dir.shareholding}%` : 'Standard NPC Director' },
                                    { label: 'ID/Passport', value: `${dir.identificationType} - ${dir.identificationNumber}` }, 
                                    { label: 'Email', value: dir.email }, 
                                    { label: 'Phone', value: dir.phone }, 
                                    { label: 'Physical Address', value: dir.physicalAddress }
                                ]} />
                            ))}
                             <ReviewSection title="Uploaded Documents" data={[
                                { label: 'Proof of Business Address', value: formData.businessAddressProof?.name || 'Not Uploaded' },
                                ...formData.directors.map(d => ({
                                    label: `ID for ${d.fullName}`,
                                    value: formData.directorIdDocuments[d.id]?.name || 'Not Uploaded'
                                }))
                            ]} />
                            <ReviewSection title="Primary Contact" data={[
                                { label: 'Full Name', value: formData.primaryContact.name }, { label: 'Email', value: formData.primaryContact.email }
                            ]} />
                             <div className="mt-8 bg-blue-50 p-4 rounded-lg border border-blue-100">
                                <p className="text-xs text-blue-800">By proceeding, you confirm that all information provided is accurate and that you are authorized to submit this registration. False information can lead to prosecution under the Companies Act.</p>
                             </div>
                         </div>
                    </Card>
                )}

                {step === 7 && (
                    <Card title="Step 7: Payment & Submission">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 text-left">
                            <div>
                                <h3 className="text-lg font-semibold text-gray-800">Service Fee</h3>
                                <div className="mt-4 space-y-2 text-sm text-gray-600">
                                    <div className="flex justify-between">
                                        <span>Official Registration (Incl. CIPC Fees)</span>
                                        <span>R 499.00</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span>Electronic Certificate (Cor14.3)</span>
                                        <span>Included</span>
                                    </div>
                                    <div className="flex justify-between font-semibold text-gray-800 border-t pt-2">
                                        <span>Total Due</span>
                                        <span>R 499.00</span>
                                    </div>
                                </div>
                                <div className="mt-6 p-4 bg-green-50 rounded-lg text-xs text-green-800">
                                    <p className="font-bold mb-1">Secure Transaction</p>
                                    <p>Your payment information is encrypted and processed via our secure partner gateway. We do not store your full card details.</p>
                                </div>
                            </div>
                            <form onSubmit={handlePaymentSubmit} className="space-y-4">
                                 <div>
                                    <Input label="Cardholder Name" id="cardholderName" value={paymentDetails.cardholderName} onChange={handlePaymentInputChange} required disabled={isPaying} className={paymentErrors.cardholderName ? 'border-red-500' : ''}/>
                                    {paymentErrors.cardholderName && <p className="mt-1 text-xs text-red-600">{paymentErrors.cardholderName}</p>}
                                </div>
                                <div>
                                    <Input label="Card Number" id="cardNumber" value={paymentDetails.cardNumber} onChange={handlePaymentInputChange} placeholder="0000 0000 0000 0000" required disabled={isPaying} className={paymentErrors.cardNumber ? 'border-red-500' : ''}/>
                                     {paymentErrors.cardNumber && <p className="mt-1 text-xs text-red-600">{paymentErrors.cardNumber}</p>}
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                     <div>
                                        <Input label="Expiry Date (MM/YY)" id="expiryDate" value={paymentDetails.expiryDate} onChange={handlePaymentInputChange} placeholder="MM/YY" required disabled={isPaying} className={paymentErrors.expiryDate ? 'border-red-500' : ''}/>
                                        {paymentErrors.expiryDate && <p className="mt-1 text-xs text-red-600">{paymentErrors.expiryDate}</p>}
                                    </div>
                                     <div>
                                        <Input label="CVC" id="cvc" value={paymentDetails.cvc} onChange={handlePaymentInputChange} placeholder="123" required disabled={isPaying} className={paymentErrors.cvc ? 'border-red-500' : ''}/>
                                        {paymentErrors.cvc && <p className="mt-1 text-xs text-red-600">{paymentErrors.cvc}</p>}
                                    </div>
                                </div>
                                <Button type="submit" isLoading={isPaying} className="w-full !py-3">
                                    {isPaying ? 'Processing Payment...' : 'Finalize Registration'}
                                </Button>
                            </form>
                        </div>
                    </Card>
                )}

                {step === 8 && (
                    <Card>
                        <div className="text-center py-12">
                            <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-green-100">
                                <svg className="h-10 w-10 text-green-600" fill="none" viewBox="0 0 24 24" strokeWidth="1.5" stroke="currentColor" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>
                            </div>
                            <h3 className="mt-4 text-2xl font-semibold leading-6 text-gray-900">Successfully Filed!</h3>
                            <div className="mt-2 max-w-xl mx-auto">
                                <p className="text-md text-gray-600">
                                    We have received your application for a <span className="font-bold">{formData.companyType}</span>. Your details have been queued for processing with CIPC.
                                </p>
                                <p className="mt-4 text-sm text-gray-500 bg-slate-50 p-2 rounded-md inline-block">
                                    Reference ID: <span className="font-mono">{transactionId}</span>
                                </p>
                                <p className="mt-6 text-sm text-slate-500">
                                    You will receive an email shortly with your application summary and next steps. Registration usually takes 3-5 business days depending on CIPC volume.
                                </p>
                            </div>
                            <div className="mt-8">
                                <Button onClick={resetWizard}>New Registration Task</Button>
                            </div>
                        </div>
                    </Card>
                )}

                {step < 8 && (
                    <div className="flex justify-between items-center pt-6">
                        <div className="flex gap-2">
                            {step > 1 && (<Button type="button" variant="secondary" onClick={prevStep} disabled={isPaying}>Back</Button>)}
                            {step === 1 && (<Button type="button" variant="secondary" onClick={() => setStep(0)}>Change Type</Button>)}
                            {step > 0 && <Button type="button" variant="danger" onClick={resetWizard} className="!bg-red-50 !text-red-600 !border-red-200 hover:!bg-red-100">Reset Wizard</Button>}
                        </div>
                        <div>
                            {step < 6 && (<Button type="button" onClick={nextStep}>Continue</Button>)}
                            {step === 6 && (<Button type="button" onClick={nextStep}>Confirm & Pay</Button>)}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

