    const [isExportingPdf, setIsExportingPdf] = useState(false);
    const [isAutoIncrement, setIsAutoIncrement] = useState(true);
    const [generatedHtml, setGeneratedHtml] = useState('');
    const [error, setError] = useState('');

    // Template State
    const [templates, setTemplates] = useState<InvoiceTemplate[]>([]);
    const [selectedTemplateId, setSelectedTemplateId] = useState<string>('');

    // Branding Profile State
    const [brandingProfiles, setBrandingProfiles] = useState<BrandingProfile[]>([]);
    const [selectedBrandingId, setSelectedBrandingId] = useState<string>('');

    const { clients } = useClients();

    // Initialize Templates & Branding from LocalStorage
    useEffect(() => {
        try {
            const storedTemplates = localStorage.getItem(TEMPLATES_STORAGE_KEY);
            if (storedTemplates) {
                setTemplates(JSON.parse(storedTemplates));
            }
            const storedBranding = localStorage.getItem(BRANDING_STORAGE_KEY);
            if (storedBranding) {
                setBrandingProfiles(JSON.parse(storedBranding));
            }
        } catch (e) {
            console.error("Failed to load storage", e);
        }
    }, []);

    // Effect for initializing and updating the invoice number when auto-increment is toggled
    useEffect(() => {
        if (isAutoIncrement) {
            const lastUsedNumber = localStorage.getItem(LAST_INVOICE_NUMBER_KEY);
            const nextNumber = lastUsedNumber ? getNextInvoiceNumber(lastUsedNumber) : DEFAULT_INVOICE_NUMBER;
            setDetails(prev => ({ ...prev, invoiceNumber: nextNumber }));
        }
    }, [isAutoIncrement]);

    const handleDetailChange = (field: keyof InvoiceDetails, value: any) => {
        setDetails(prev => ({ ...prev, [field]: value }));
    };

    const handleItemChange = (id: number, field: keyof InvoiceItem, value: string | number) => {
        setDetails(prev => ({
            ...prev,
            items: prev.items.map(item =>
                item.id === id ? { ...item, [field]: value } : item
            )
        }));
    };

    const addItem = () => {
        setDetails(prev => ({
            ...prev,
            items: [...prev.items, { id: Date.now(), description: '', quantity: 1, unitPrice: 0 }]
        }));
    };

    const removeItem = (id: number) => {
        setDetails(prev => ({
            ...prev,
            items: prev.items.filter(item => item.id !== id)
        }));
    };

    const handleClientSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const clientId = e.target.value;
        const selectedClient = clients.find(c => c.id === clientId);
        if (selectedClient) {
            setDetails(prev => ({
                ...prev,
                toName: selectedClient.name,
                toAddress: selectedClient.address,
            }));
        }
    };

    const handleLogoFileSelect = (file: File) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64String = reader.result as string;
          handleDetailChange('companyLogo', base64String);
          setError('');
        };
        reader.onerror = () => {
            setError('Failed to read the image file.');
        }
        reader.readAsDataURL(file);
    };

    const removeLogo = () => {
        handleDetailChange('companyLogo', '');
    };

    const handleResetForm = () => {
        if (window.confirm("Are you sure you want to reset the form? All unsaved details will be cleared.")) {
            const lastUsedNumber = localStorage.getItem(LAST_INVOICE_NUMBER_KEY);
            const nextNumber = lastUsedNumber ? getNextInvoiceNumber(lastUsedNumber) : DEFAULT_INVOICE_NUMBER;
            setDetails({
                ...initialDetails,
                invoiceNumber: nextNumber,
                date: new Date().toISOString().split('T')[0]
            });
            setSelectedTemplateId('');
            setSelectedBrandingId('');
            setGeneratedHtml('');
        }
    };

    const handleApplyStarter = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const starterId = e.target.value;
        if (!starterId) return;

        const starter = STARTER_TEMPLATES.find(s => s.id === starterId);
        if (starter) {
            if (window.confirm(`Apply the "${starter.name}" template? This will replace your current line items and notes.`)) {
                setDetails(prev => ({
                    ...prev,
                    ...starter.details,
                    // Keep existing identity and sequence
                    fromName: prev.fromName,
                    fromAddress: prev.fromAddress,
                    invoiceNumber: prev.invoiceNumber,
                    date: prev.date,
                    companyLogo: prev.companyLogo
                }));
            }
        }
        // Reset dropdown after apply
        e.target.value = "";
    };

    // --- Template Handlers ---

    const handleSaveTemplate = (isUpdate: boolean = false) => {
        let name = "";
        // FIX: Explicitly type id as string to fix type error when re-assigning from existing.id
        let id: string = crypto.randomUUID();

        if (isUpdate && selectedTemplateId) {
            const existing = templates.find(t => t.id === selectedTemplateId);
            if (existing) {
                name = existing.name;
                id = existing.id;
            }
        } else {
            const inputName = window.prompt("Enter a name for this invoice template:");
            if (!inputName) return;
            name = inputName;
        }

        const newTemplate: InvoiceTemplate = {
            id,
            name,
            details: { ...details }
        };

        let updatedTemplates: InvoiceTemplate[];
        if (isUpdate) {
            updatedTemplates = templates.map(t => t.id === id ? newTemplate : t);
        } else {
            updatedTemplates = [...templates, newTemplate];
        }

        setTemplates(updatedTemplates);
        localStorage.setItem(TEMPLATES_STORAGE_KEY, JSON.stringify(updatedTemplates));
        setSelectedTemplateId(id);
        alert(isUpdate ? "Template updated successfully!" : "Template saved successfully!");
    };

    const handleLoadTemplate = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const templateId = e.target.value;
        setSelectedTemplateId(templateId);

        if (!templateId) return;

        const template = templates.find(t => t.id === templateId);
        if (template) {
            setDetails(prev => ({
                ...template.details,
                invoiceNumber: prev.invoiceNumber,
                date: prev.date
            }));
        }
    };

    const handleDeleteTemplate = () => {
        if (!selectedTemplateId) return;
        if (window.confirm("Are you sure you want to delete this template?")) {
            const updatedTemplates = templates.filter(t => t.id !== selectedTemplateId);
            setTemplates(updatedTemplates);
            localStorage.setItem(TEMPLATES_STORAGE_KEY, JSON.stringify(updatedTemplates));
            setSelectedTemplateId('');
        }
    };

    // --- Branding Profile Handlers ---

    const handleSaveBranding = (isUpdate: boolean = false) => {
        let name = "";
        // FIX: Explicitly type id as string to fix type error when re-assigning from existing.id
        let id: string = crypto.randomUUID();

        if (isUpdate && selectedBrandingId) {
            const existing = brandingProfiles.find(p => p.id === selectedBrandingId);
            if (existing) {
                name = existing.name;
                id = existing.id;
            }
        } else {
            const inputName = window.prompt("Enter a name for these branding settings:");
            if (!inputName) return;
            name = inputName;
        }

        const newProfile: BrandingProfile = {
            id,
            name,
            details: {
                companyLogo: details.companyLogo || '',
                header: details.header || '',
                footer: details.footer || '',
                bankDetails: details.bankDetails || '',
                notes: details.notes || '',
                paymentTerms: details.paymentTerms || ''
            }
        };

        let updatedProfiles: BrandingProfile[];
        if (isUpdate) {
            updatedProfiles = brandingProfiles.map(p => p.id === id ? newProfile : p);
        } else {
            updatedProfiles = [...brandingProfiles, newProfile];
        }

        setBrandingProfiles(updatedProfiles);
        localStorage.setItem(BRANDING_STORAGE_KEY, JSON.stringify(updatedProfiles));
        setSelectedBrandingId(id);
        alert(isUpdate ? "Branding updated successfully!" : "Branding saved successfully!");
    };

    const handleLoadBranding = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const profileId = e.target.value;
        setSelectedBrandingId(profileId);

        if (!profileId) return;

        const profile = brandingProfiles.find(p => p.id === profileId);
        if (profile) {
            setDetails(prev => ({
                ...prev,
                companyLogo: profile.details.companyLogo,
                header: profile.details.header,
                footer: profile.details.footer,
                bankDetails: profile.details.bankDetails,
                notes: profile.details.notes,
                paymentTerms: profile.details.paymentTerms
            }));
        }
    };

    const handleDeleteBranding = () => {
        if (!selectedBrandingId) return;
        if (window.confirm("Are you sure you want to delete these branding settings?")) {
            const updatedProfiles = brandingProfiles.filter(p => p.id !== selectedBrandingId);
            setBrandingProfiles(updatedProfiles);
            localStorage.setItem(BRANDING_STORAGE_KEY, JSON.stringify(updatedProfiles));
            setSelectedBrandingId('');
        }
    };

    const handleSubmit = async () => {
        setLoading(true);
        setError('');
        setGeneratedHtml('');
        try {
            const html = await generateInvoiceHtml(details);
            setGeneratedHtml(html);

            if (isAutoIncrement) {
                const usedNumber = details.invoiceNumber;
                localStorage.setItem(LAST_INVOICE_NUMBER_KEY, usedNumber);
                const nextNumber = getNextInvoiceNumber(usedNumber);
                setDetails(prev => ({ ...prev, invoiceNumber: nextNumber }));
            }
        } catch (err: any) {
            setError(err.message || 'An unexpected error occurred.');
        } finally {
            setLoading(false);
        }
    };

    const handleExportPdf = async () => {
        if (!generatedHtml) return;
        setIsExportingPdf(true);
        setError('');
        try {
            const invoiceElement = document.getElementById('invoice-preview-content');
            if (!invoiceElement) {
                setError('Could not find invoice element to export.');
                setIsExportingPdf(false);
                return;
            }

            const { jsPDF } = window.jspdf;
            const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
            const canvas = await window.html2canvas(invoiceElement, { scale: 2, useCORS: true });
            const imgData = canvas.toDataURL('image/png');
            const margin = 15;
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const pdfHeight = pdf.internal.pageSize.getHeight();
            const usableWidth = pdfWidth - margin * 2;
            const scaledHeight = usableWidth / (canvas.width / canvas.height);
            let heightLeft = scaledHeight;
            let position = 0;
            const usablePageHeight = pdfHeight - margin * 2;
            pdf.addImage(imgData, 'PNG', margin, margin, usableWidth, scaledHeight);
            heightLeft -= usablePageHeight;
            while (heightLeft > 0) {
                position -= usablePageHeight;
                pdf.addPage();
                pdf.addImage(imgData, 'PNG', margin, position + margin, usableWidth, scaledHeight);
                heightLeft -= usablePageHeight;
            }
            pdf.save(`invoice-${details.invoiceNumber}.pdf`);
        } catch (err) {
            setError('Failed to export PDF.');
        } finally {
            setIsExportingPdf(false);
        }
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <Card title="Invoice Builder" className="h-fit">
                <div className="space-y-6">
                    {/* TOP ACTION BAR */}
                    <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center bg-slate-50 p-3 rounded-lg border border-slate-200 gap-3">
                        <div className="flex-1 w-full">
                            <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Starter Template</label>
                            <select 
                                onChange={handleApplyStarter}
                                className="block w-full py-1.5 px-3 border border-slate-300 bg-white rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 text-xs"
                            >
                                <option value="">-- Choose Starter --</option>
                                {STARTER_TEMPLATES.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                        <Button variant="secondary" onClick={handleResetForm} className="!py-2 !px-4 text-xs flex items-center gap-2 w-full sm:w-auto">
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                             Clear Form
                        </Button>
                    </div>

                    {/* SAVED TEMPLATE MANAGER */}
                    <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100">
                        <div className="flex flex-col gap-3">
                            <label htmlFor="template-select" className="block text-xs font-bold text-indigo-700 uppercase tracking-wider">My Saved Templates</label>
                            <div className="flex gap-2">
                                <select 
                                    id="template-select" 
                                    value={selectedTemplateId} 
                                    onChange={handleLoadTemplate} 
                                    className="block w-full py-2 px-3 border border-indigo-200 bg-white rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                >
                                    <option value="">-- Select Template --</option>
                                    {templates.map(t => (
                                        <option key={t.id} value={t.id}>{t.name}</option>
                                    ))}
                                </select>
                                {selectedTemplateId && (
                                    <Button variant="danger" onClick={handleDeleteTemplate} className="!p-2 text-sm" title="Delete Template">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                    </Button>
                                )}
                            </div>
                            <div className="flex gap-2">
                                {selectedTemplateId ? (
                                    <>
                                        <Button variant="secondary" onClick={() => handleSaveTemplate(true)} className="flex-1 !py-2 text-xs">Update Selected</Button>
                                        <Button variant="secondary" onClick={() => handleSaveTemplate(false)} className="flex-1 !py-2 text-xs">Save as New</Button>
                                    </>
                                ) : (
                                    <Button variant="secondary" onClick={() => handleSaveTemplate(false)} className="w-full !py-2 text-xs">Save Current as Template</Button>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* VISUAL THEMES */}
                    <div className="p-4 bg-white border border-slate-200 rounded-xl space-y-3">
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Visual Theme</label>
                         <div className="grid grid-cols-4 gap-2">
                             {THEMES.map(theme => (
                                 <button
                                    key={theme.id}
                                    onClick={() => handleDetailChange('theme', theme.id)}
                                    className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 transition-all ${details.theme === theme.id ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 hover:border-slate-200'}`}
                                 >
                                    <span className="text-xl mb-1">{theme.icon}</span>
                                    <span className="text-[10px] font-semibold text-slate-600">{theme.name}</span>
                                 </button>
                             ))}
                         </div>
                    </div>

                    {/* FROM/TO SECTION */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-2">
                        <fieldset className="space-y-4">
                            <legend className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-2">From</legend>
                            <Input label="Business Name" id="fromName" value={details.fromName} onChange={e => handleDetailChange('fromName', e.target.value)} />
                            <TextArea label="Address" id="fromAddress" value={details.fromAddress} onChange={e => handleDetailChange('fromAddress', e.target.value)} rows={2} />
                            <Input label="Reg No." id="fromBusinessNumber" value={details.fromBusinessNumber || ''} onChange={e => handleDetailChange('fromBusinessNumber', e.target.value)} placeholder="2023/123456/07" />
                            <Input label="VAT No." id="fromVatNumber" value={details.fromVatNumber || ''} onChange={e => handleDetailChange('fromVatNumber', e.target.value)} />
                        </fieldset>
                        <fieldset className="space-y-4">
                            <legend className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-2">To</legend>
                            <div className="mb-2">
                                <label className="block text-xs font-medium text-gray-500 mb-1">Quick Select Client</label>
                                <select onChange={handleClientSelect} className="form-input text-xs">
                                    <option value="">-- Choose Client --</option>
                                    {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                </select>
                            </div>
                            <Input label="Client Name" id="toName" value={details.toName} onChange={e => handleDetailChange('toName', e.target.value)} />
                            <TextArea label="Address" id="toAddress" value={details.toAddress} onChange={e => handleDetailChange('toAddress', e.target.value)} rows={2} />
                        </fieldset>
                    </div>

                    {/* INVOICE SETTINGS */}
                    <fieldset className="grid grid-cols-2 gap-4 border-t border-slate-100 pt-6">
                        <div className="col-span-2 sm:col-span-1">
                            <Input 
                                label="Invoice #" 
                                id="invoiceNumber" 
                                value={details.invoiceNumber} 
                                onChange={e => handleDetailChange('invoiceNumber', e.target.value)}
                                readOnly={isAutoIncrement}
                                className={isAutoIncrement ? 'bg-slate-50 cursor-not-allowed' : ''}
                            />
                            <label className="mt-1 flex items-center cursor-pointer">
                                <input type="checkbox" checked={isAutoIncrement} onChange={e => setIsAutoIncrement(e.target.checked)} className="h-3 w-3 rounded border-gray-300 text-indigo-600" />
                                <span className="ml-2 text-[10px] text-gray-500 font-medium">Auto-increment</span>
                            </label>
                        </div>
                        <Input label="Date" id="date" type="date" value={details.date} onChange={e => handleDetailChange('date', e.target.value)} />
                        <div className="col-span-2">
                            <Input label="Payment Terms" id="paymentTerms" value={details.paymentTerms || ''} onChange={e => handleDetailChange('paymentTerms', e.target.value)} placeholder="e.g., Net 30" />
                        </div>
                    </fieldset>

                    {/* BRANDING SECTION */}
                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 space-y-4">
                        <div className="flex flex-col gap-3">
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Branding Profile</label>
                            <div className="flex gap-2">
                                <select 
                                    value={selectedBrandingId} 
                                    onChange={handleLoadBranding} 
                                    className="block w-full py-1.5 px-3 border border-gray-300 bg-white rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 text-xs"
                                >
                                    <option value="">-- Load Profile --</option>
                                    {brandingProfiles.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                                </select>
                                {selectedBrandingId && (
                                    <Button variant="danger" onClick={handleDeleteBranding} className="!p-1.5" title="Delete Branding">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                    </Button>
                                )}
                            </div>
                            <div className="flex gap-2">
                                {selectedBrandingId ? (
                                    <>
                                        <Button variant="secondary" onClick={() => handleSaveBranding(true)} className="flex-1 !py-1.5 text-[10px]">Update Profile</Button>
                                        <Button variant="secondary" onClick={() => handleSaveBranding(false)} className="flex-1 !py-1.5 text-[10px]">Save as New</Button>
                                    </>
                                ) : (
                                    <Button variant="secondary" onClick={() => handleSaveBranding(false)} className="w-full !py-1.5 text-[10px]">Save Branding Profile</Button>
                                )}
                            </div>
                        </div>

                        <div className="pt-2">
                            <label className="block text-xs font-semibold text-gray-700 mb-2">Logo</label>
                            {details.companyLogo ? (
                                <div className="flex items-center gap-3 bg-white p-2 rounded border border-slate-100">
                                    <img src={details.companyLogo} alt="Logo" className="h-10 w-10 object-contain" />
                                    <button onClick={removeLogo} className="text-[10px] text-red-500 hover:underline">Remove</button>
                                </div>
                            ) : (
                                <FileUpload label="Upload Logo" id="logo-upload" onFileSelect={handleLogoFileSelect} onFileRemove={() => {}} currentFile={null} acceptedFileTypes="image/*" />
                            )}
                        </div>
                    </div>

                    {/* ITEMS */}
                    <fieldset className="space-y-3">
                        <legend className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-2">Line Items</legend>
                        {details.items.map((item, index) => (
                            <div key={item.id} className="grid grid-cols-12 gap-2 p-3 bg-slate-50 rounded-lg border border-slate-200">
                                <div className="col-span-12 sm:col-span-6">
                                    <Input label="Description" id={`item-desc-${item.id}`} value={item.description} onChange={e => handleItemChange(item.id, 'description', e.target.value)} className="text-xs" />
                                </div>
                                <div className="col-span-4 sm:col-span-2">
                                    <Input label="Qty" type="number" id={`item-qty-${item.id}`} value={item.quantity} onChange={e => handleItemChange(item.id, 'quantity', Number(e.target.value))} className="text-xs" />
                                </div>
                                <div className="col-span-5 sm:col-span-3">
                                    <Input label="Price" type="number" id={`item-price-${item.id}`} value={item.unitPrice} onChange={e => handleItemChange(item.id, 'unitPrice', Number(e.target.value))} className="text-xs" />
                                </div>
                                <div className="col-span-3 sm:col-span-1 flex items-end justify-center pb-2">
                                    <button onClick={() => removeItem(item.id)} className="text-red-400 hover:text-red-600"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg></button>
                                </div>
                            </div>
                        ))}
                        <Button variant="secondary" onClick={addItem} className="w-full !py-2 text-xs">+ Add Item</Button>
                    </fieldset>

                    <Button onClick={handleSubmit} isLoading={loading} className="w-full !py-4 text-lg">Generate Invoice</Button>
                </div>
            </Card>

            {/* PREVIEW PANEL */}
            <Card title="Invoice Preview" className="lg:sticky lg:top-8 h-fit">
                {loading ? (
                    <div className="flex flex-col items-center justify-center p-20"><Spinner /><p className="mt-4 text-slate-500 animate-pulse">Crafting your professional invoice...</p></div>
                ) : generatedHtml ? (
                    <div className="space-y-4">
                        <div className="flex justify-end gap-2">
                            <Button variant="secondary" onClick={handleExportPdf} isLoading={isExportingPdf} className="!py-1.5 text-xs">Download PDF</Button>
                            <Button variant="secondary" onClick={() => window.print()} className="!py-1.5 text-xs">Print</Button>
                        </div>
                        <div id="invoice-preview-content" className="border shadow-inner p-4 bg-white rounded-lg min-h-[600px]" dangerouslySetInnerHTML={{ __html: generatedHtml }} />
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center p-20 text-slate-400 border-2 border-dashed border-slate-100 rounded-xl">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        <p className="text-center font-medium">Ready for your magic touch.</p>
                        <p className="text-center text-xs mt-1">Fill the form and hit "Generate Invoice".</p>
                    </div>
                )}
                {error && <div className="mt-4 p-4 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100">{error}</div>}
            </Card>
        </div>
    );
};

