  const baseClasses = "relative inline-flex items-center justify-center px-6 py-3 text-sm font-bold rounded-xl transition-all duration-300 active:scale-[0.97] focus:outline-none focus:ring-4 disabled:opacity-50 disabled:pointer-events-none overflow-hidden";

