    primary: "text-white bg-indigo-600 hover:bg-indigo-700 hover:shadow-lg hover:shadow-indigo-200 focus:ring-indigo-100",
    secondary: "text-indigo-700 bg-indigo-50 hover:bg-indigo-100 hover:shadow-md focus:ring-indigo-50",
