{
  "name": "SMEPal | Professional Business Assistant",
  "description": "An AI-powered assistant for South African Small and Medium-sized Enterprises (SMEs) to help with generating invoices, calculating taxes, drafting contracts, and managing payroll reminders.",
  "requestFramePermissions": [
