                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
                        </div>
                        <div>
                            <h2 className="font-black text-xl tracking-tight leading-none mb-1">Business Advisor</h2>
                            <p className="text-indigo-200 text-[10px] font-bold uppercase tracking-widest">Premium Intelligence Engine</p>
                        </div>
                    </div>
                    <button 
                        onClick={() => isVoiceMode ? stopVoiceMode() : startVoiceMode()}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${isVoiceMode ? 'bg-rose-500 text-white animate-pulse' : 'bg-white/10 hover:bg-white/20 text-white border border-white/20'}`}
                    >
                        <div className={`h-2 w-2 rounded-full ${isVoiceMode ? 'bg-white' : 'bg-emerald-400'}`}></div>
                        {isVoiceMode ? 'Voice: ACTIVE' : 'Enable Voice'}
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50">
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[85%] rounded-[1.5rem] px-5 py-4 shadow-sm transition-all animate-fade-in-up ${
                                msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none font-medium'
                            }`}>
                                <p className="whitespace-pre-wrap text-sm leading-relaxed">{msg.text}</p>
                            </div>
                        </div>
                    ))}
                    {isVoiceMode && (
                        <div className="flex justify-center py-10">
                            <div className="flex items-center gap-1">
                                {[...Array(8)].map((_, i) => (
                                    <div key={i} className="w-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ height: `${Math.random() * 40 + 10}px`, animationDelay: `${i * 0.1}s` }}></div>
                                ))}
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                <div className="p-6 bg-white border-t border-slate-100">
                    <form onSubmit={handleSubmit} className="relative group">
                        <textarea
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSubmit(e as any))}
                            placeholder="Ask about strategy, compliance, or marketing..."
                            className="w-full pl-6 pr-14 py-4 rounded-2xl border-2 border-slate-100 focus:border-indigo-500 focus:ring-0 resize-none shadow-sm text-sm font-medium transition-all"
                            rows={2}
                            disabled={isLoading || isVoiceMode}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim() || isVoiceMode}
                            className="absolute right-3 top-3.5 p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:bg-slate-200 disabled:text-slate-400 transition-all shadow-lg shadow-indigo-200"
