import React, { useState, useMemo } from 'react';
import Card from './common/Card';
import Input from './common/Input';
import Button from './common/Button';
import Spinner from './common/Spinner';
import { calculateTax } from '../services/geminiService';
import type { TaxCalculationResult } from '../types';

const formatCurrency = (value: string | number | undefined) => {
    if (value === undefined || value === null) return '0.00';
    const num = Number(value);
    if (isNaN(num)) return String(value);
    return num.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const TaxGauge: React.FC<{ percentage: number }> = ({ percentage }) => {
    const radius = 80;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (percentage / 100) * circumference;
    const color = percentage < 15 ? '#10b981' : percentage < 30 ? '#f59e0b' : '#ef4444';

    return (
        <div className="relative flex items-center justify-center">
            <svg className="h-48 w-48 transform -rotate-90">
                <circle cx="96" cy="96" r={radius} stroke="#f1f5f9" strokeWidth="12" fill="transparent" />
                <circle 
                    cx="96" cy="96" r={radius} stroke={color} strokeWidth="12" fill="transparent" 
                    strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round"
                    className="transition-all duration-1000 ease-out"
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-3xl font-black text-slate-900">{percentage.toFixed(1)}%</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase">Effective Rate</span>
            </div>
        </div>
    );
};

const TaxCalculator = () => {
    const [income, setIncome] = useState<number>(500000);
    const [expenses, setExpenses] = useState<number>(120000);
    const [deductions, setDeductions] = useState<number>(35000);
    const [credits, setCredits] = useState<number>(17235);
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<TaxCalculationResult | null>(null);
    const [error, setError] = useState('');

    const effectiveRate = useMemo(() => {
        if (!result) return 0;
        const tax = Number(result.estimatedTax);
        return (tax / income) * 100;
    }, [result, income]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setResult(null);
        try {
            const taxResult = await calculateTax(income, expenses, deductions, credits);
            setResult(taxResult);
        } catch (err: any) {
            setError(err.message || "An unexpected error occurred.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 pb-16">
            <div className="text-left space-y-2">
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">Tax Estimator</h1>
                <p className="text-slate-500 font-medium">Plan your cash flow with intelligence. Based on 2024/2025 SARS brackets.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <Card className="lg:col-span-1 rounded-[2.5rem] p-8 shadow-xl border-0">
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <Input label="Annual Gross Income (R)" id="income" type="number" value={income} onChange={e => setIncome(Number(e.target.value))} required tooltip="Total earnings before any tax." />
                        <Input label="Business Expenses (R)" id="expenses" type="number" value={expenses} onChange={e => setExpenses(Number(e.target.value))} required tooltip="Legitimate costs like rent/data." />
                        <Input label="Annual Deductions (R)" id="deductions" type="number" value={deductions} onChange={e => setDeductions(Number(e.target.value))} required tooltip="Allowable deductions (e.g. RA)." />
                        <Input label="Annual Rebates (R)" id="credits" type="number" value={credits} onChange={e => setCredits(Number(e.target.value))} required tooltip="Direct reductions (Primary rebate: R17,235)." />
                        <Button type="submit" isLoading={loading} className="w-full !py-4 shadow-xl shadow-indigo-100 rounded-2xl">Analyze Tax Burden</Button>
                    </form>
                </Card>

                <Card className="lg:col-span-2 rounded-[2.5rem] bg-white shadow-2xl border-0 relative overflow-hidden flex flex-col justify-center min-h-[500px]">
                    {loading ? (
                        <div className="flex flex-col items-center"><Spinner /><p className="mt-4 font-bold text-slate-400 animate-pulse uppercase tracking-widest text-xs">Simulating SARS Assessment...</p></div>
                    ) : result ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-10 p-10 animate-fade-in">
                            <div className="flex flex-col items-center justify-center space-y-4">
                                <TaxGauge percentage={effectiveRate} />
                                <div className="text-center">
                                    <p className="text-xs font-black text-emerald-600 uppercase mb-1">Status: Healthy</p>
                                    <p className="text-sm text-slate-500 leading-relaxed font-medium">Your tax planning is efficient. You are leveraging standard deductions effectively.</p>
                                </div>
                            </div>
                            <div className="space-y-8 border-l border-slate-100 pl-10">
                                <div>
                                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Net Taxable Income</h3>
                                    <p className="text-4xl font-black text-slate-900">R {formatCurrency(result.taxableIncome)}</p>
                                </div>
                                <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-2xl shadow-indigo-200">
                                    <h3 className="text-xs font-black text-indigo-200 uppercase tracking-widest mb-2">Estimated Annual Tax</h3>
                                    <p className="text-5xl font-black">R {formatCurrency(result.estimatedTax)}</p>
                                    <p className="text-[10px] font-bold text-indigo-300 mt-4 uppercase tracking-tighter">Approx. R {formatCurrency(Number(result.estimatedTax)/12)} / Month</p>
                                </div>
                                <div className="pt-2">
                                     <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest mb-4">AI Observations:</h4>
                                     <ul className="space-y-2">
                                         {result.notes.map((n, i) => (
                                             <li key={i} className="flex gap-3 text-xs text-slate-500 font-medium italic">
                                                 <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 mt-1 flex-shrink-0"></div>
                                                 {n}
                                             </li>
                                         ))}
                                     </ul>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="text-center text-slate-300 p-20">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 mx-auto opacity-10 mb-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 7h6m0 10v-3m-3 3h3m-3-10h.01M9 17h.01M12 17h.01M15 17h.01M9 14h.01M12 14h.01M15 14h.01M4 7v10a2 2 0 002 2h12a2 2 0 002-2V7a2 2 0 00-2-2H6a2 2 0 00-2 2z" /></svg>
                            <p className="font-bold uppercase tracking-widest text-xs">Enter details to see visualization</p>
                        </div>
                    )}
                </Card>
            </div>
        </div>
    );
};

