        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        const stored = localStorage.getItem('sme-pal-expenses');
        if (stored) setExpenses(JSON.parse(stored));
        return () => clearInterval(timer);
    }, []);

    const monthlySpend = useMemo(() => {
        const now = new Date();
        return expenses
            .filter(e => new Date(e.date).getMonth() === now.getMonth())
            .reduce((sum, e) => sum + e.amount, 0);
    }, [expenses]);

    const handleGetTip = async () => {
        setLoadingTip(true);
        try {
            const tip = await getDailyBusinessTip();
            setDailyTip(tip);
        } catch (e) {
            setDailyTip("Focus on providing value, and success will follow naturally.");
        } finally {
            setLoadingTip(false);
        }
