import React, { useState, useMemo } from 'react';
import Card from './common/Card';
import Input from './common/Input';
import Button from './common/Button';
import Spinner from './common/Spinner';
import { calculateTax } from '../services/geminiService';
import type { TaxCalculationResult } from '../types';

const formatCurrency = (value: string | number | undefined) => {
    if (value === undefined || value === null) return '0.00';
    const num = Number(value);
    if (isNaN(num)) return String(value);
    return num.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const TaxGauge: React.FC<{ percentage: number }> = ({ percentage }) => {
    const radius = 70;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (percentage / 100) * circumference;
    const color = percentage < 15 ? '#10b981' : percentage < 30 ? '#f59e0b' : '#ef4444';

    return (
        <div className="relative flex items-center justify-center">
            <svg className="h-40 w-40 transform -rotate-90">
                <circle cx="80" cy="80" r={radius} stroke="#f8fafc" strokeWidth="6" fill="transparent" />
                <circle 
                    cx="80" cy="80" r={radius} stroke={color} strokeWidth="6" fill="transparent" 
                    strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round"
                    className="transition-all duration-1000 ease-out"
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-2xl font-black text-slate-900">{percentage.toFixed(1)}%</span>
                <span className="text-[9px] font-extrabold text-slate-400 uppercase tracking-widest">Effective</span>
            </div>
        </div>
    );
};

const TaxCalculator = () => {
    const [income, setIncome] = useState<number>(500000);
    const [expenses, setExpenses] = useState<number>(120000);
    const [deductions, setDeductions] = useState<number>(35000);
    const [credits, setCredits] = useState<number>(17235);
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<TaxCalculationResult | null>(null);
    const [error, setError] = useState('');

    const effectiveRate = useMemo(() => {
        if (!result) return 0;
        const tax = Number(result.estimatedTax);
        return (tax / income) * 100;
    }, [result, income]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setResult(null);
        try {
            const taxResult = await calculateTax(income, expenses, deductions, credits);
            setResult(taxResult);
        } catch (err: any) {
            setError(err.message || "Tax engine connection error.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-5xl mx-auto space-y-8 pb-16">
            <div className="text-left space-y-1">
                <h1 className="text-2xl font-extrabold text-slate-900 tracking-tight uppercase tracking-widest text-[20px]">Taxation Estimator</h1>
                <p className="text-slate-500 font-medium text-[14px]">Strategic forecasting based on 2024/2025 SARS legislative brackets.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                <div className="lg:col-span-4 space-y-6">
                    <Card title="Input Telemetry" className="shadow-none">
                        <form onSubmit={handleSubmit} className="space-y-5">
                            <Input label="Annual Gross (R)" id="income" type="number" value={income} onChange={e => setIncome(Number(e.target.value))} className="form-input-minimal" required />
                            <Input label="Operational Costs (R)" id="expenses" type="number" value={expenses} onChange={e => setExpenses(Number(e.target.value))} className="form-input-minimal" required />
                            <Input label="Legal Deductions (R)" id="deductions" type="number" value={deductions} onChange={e => setDeductions(Number(e.target.value))} className="form-input-minimal" required />
                            <Input label="Total Credits (R)" id="credits" type="number" value={credits} onChange={e => setCredits(Number(e.target.value))} className="form-input-minimal" required />
                            <Button type="submit" isLoading={loading} className="w-full !rounded-md !py-3">Authorize Calculation</Button>
                        </form>
                    </Card>
                </div>

                <div className="lg:col-span-8">
                    <div className="bg-white card-elevation rounded-2xl p-0 overflow-hidden flex flex-col justify-center min-h-[500px]">
                        {loading ? (
                            <div className="flex flex-col items-center justify-center p-20">
                                <Spinner />
                                <p className="mt-6 text-[10px] font-extrabold text-slate-400 uppercase tracking-[0.2em] animate-pulse">Consulting SARS Engine...</p>
                            </div>
                        ) : result ? (
                            <div className="animate-soft-reveal flex flex-col h-full">
                                <div className="p-10 border-b border-slate-50 flex flex-col md:flex-row items-center justify-between gap-8">
                                    <TaxGauge percentage={effectiveRate} />
                                    <div className="flex-1 text-center md:text-right space-y-1">
                                        <p className="text-[10px] font-extrabold text-indigo-500 uppercase tracking-widest">Tax Liability</p>
                                        <p className="text-5xl font-black text-slate-900 tracking-tighter">R {formatCurrency(result.estimatedTax)}</p>
                                        <p className="text-[12px] font-bold text-slate-400 italic">Net taxable: R {formatCurrency(result.taxableIncome)}</p>
                                    </div>
                                </div>
                                <div className="p-10 bg-slate-50/50 flex-1">
                                     <h4 className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest mb-6">Legislative Observations</h4>
                                     <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                         {result.notes.map((n, i) => (
                                             <div key={i} className="bg-white p-4 rounded-lg border border-slate-200/60 shadow-sm flex gap-3 items-start">
                                                 <div className="h-1.5 w-1.5 rounded-full bg-indigo-500 mt-1.5 flex-shrink-0"></div>
                                                 <p className="text-[12px] text-slate-600 font-medium leading-relaxed">{n}</p>
                                             </div>
                                         ))}
                                     </div>
                                </div>
                            </div>
                        ) : (
                            <div className="text-center p-20">
                                <div className="h-16 w-16 bg-slate-50 text-slate-200 rounded-xl flex items-center justify-center mx-auto mb-6">
                                    <svg className="h-8 w-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeWidth="2.5" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                </div>
                                <p className="text-[12px] font-extrabold text-slate-400 uppercase tracking-[0.2em]">Awaiting Telemetry</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default TaxCalculator;
